SELECT
    r.id, r.role_name, r.role_code, r.role_desc, r.role_type, r.status, r.sort,
    r.data_scope, r.role_level, r.is_system, r.is_deletable, r.is_editable,
    r.role_icon, r.role_color, r.ext_data, r.create_time, r.update_time,
    r.create_by, r.update_by, r.remark,
    COUNT(DISTINCT ur.user_id) as user_count
FROM sys_role r
LEFT JOIN sys_user_role ur ON r.id = ur.role_id

    r.deleted = 0

        AND r.role_name LIKE CONCAT('%', #{query.roleName}, '%')


        AND r.role_code LIKE CONCAT('%', #{query.roleCode}, '%')


        AND r.status = #{query.status}


        AND r.role_type = #{query.roleType}


        AND r.role_level = #{query.roleLevel}


        AND r.is_system = #{query.isSystem}


        AND r.data_scope = #{query.dataScope}


        AND r.create_time >= #{query.startTime}


        AND r.create_time <= #{query.endTime}


GROUP BY r.id
ORDER BY r.sort ASC, r.create_time DESC

SELECT COUNT(*)
FROM sys_role r

    r.deleted = 0

        AND r.role_name LIKE CONCAT('%', #{query.roleName}, '%')


        AND r.role_code LIKE CONCAT('%', #{query.roleCode}, '%')


        AND r.status = #{query.status}


        AND r.role_type = #{query.roleType}


        AND r.role_level = #{query.roleLevel}


        AND r.is_system = #{query.isSystem}


        AND r.data_scope = #{query.dataScope}


        AND r.create_time >= #{query.startTime}


        AND r.create_time <= #{query.endTime}
